{
  "competency_groups": [
    {
      "code": "BIO-U6-C1",
      "title": "Sexual Reproduction in Flowering Plants",
      "description": "Understanding the structural and functional aspects of flowering plant reproduction, including gametophyte development, pollination mechanisms, double fertilization, and special reproductive modes.",
      "competencies": [
        "Analyze flower structure and the developmental processes of male and female gametophytes."
      ],
      "unit_name": "Reproduction",
      "chapter_name": "Sexual Reproduction in Flowering Plants"
    },
    {
      "code": "BIO-U6-C2",
      "title": "Human Reproduction",
      "description": "Exploring the anatomy and physiology of human reproductive systems, gametogenesis, hormonal regulation of the menstrual cycle, fertilization, and post-fertilization events.",
      "competencies": [
        "Evaluate the microscopic anatomy of male and female reproductive organs and their functional roles."
      ],
      "unit_name": "Reproduction",
      "chapter_name": "Human Reproduction"
    },
    {
      "code": "BIO-U6-C3",
      "title": "Reproductive Health",
      "description": "Assessing the importance of reproductive health, methods of contraception, prevention and management of STDs, MTP, assisted reproductive technologies, and genetic screening.",
      "competencies": [
        "Critique various birth control methods and their implications for public health."
      ],
      "unit_name": "Reproduction",
      "chapter_name": "Reproductive Health"
    },
    {
      "code": "BIO-U7-C1",
      "title": "Principles of Inheritance and Variation",
      "description": "Investigating the laws of inheritance, deviations from Mendelian genetics, chromosomal theory, sex determination mechanisms, and genetic disorders.",
      "competencies": [
        "Apply principles of Mendelian inheritance to analyze complex traits including incomplete dominance and co-dominance."
      ],
      "unit_name": "Genetics and Evolution",
      "chapter_name": "Principles of Inheritance and Variation"
    },
    {
      "code": "BIO-U7-C2",
      "title": "Molecular Basis of Inheritance",
      "description": "Examining the molecular nature of genetic material, DNA structure, replication mechanisms, gene expression regulation via operons, and applications in genomics.",
      "competencies": [
        "Explain the Central Dogma and its role in converting genetic information into functional proteins."
      ],
      "unit_name": "Genetics and Evolution",
      "chapter_name": "Molecular Basis of Inheritance"
    }
  ]
}
